# fix_finanzas.ps1 - Tesoreria y SEPA con botones funcionales
Write-Host "Aplicando fixes en Finanzas..." -ForegroundColor Cyan

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\finance\pages\tabs\TesoreriaTab.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/modules/finance/pages/tabs/TesoreriaTab.tsx" -ForegroundColor Yellow

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\finance\pages\tabs\SEPATab.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/modules/finance/pages/tabs/SEPATab.tsx" -ForegroundColor Yellow

Write-Host "Finanzas listo!" -ForegroundColor Green
